    state.reset_hook_count();
    // C: L->hookmask = cast_byte(mask)
    // macros.tsv: cast_byte(x) → x as u8
    state.set_hook_mask(mask as u8);
    // C: if (mask) settraps(L->ci)
    if mask != 0 {
        set_traps(state);
    }
}

